<?php
declare(strict_types=1);

function help_articles():array{return [
 'getting-started'=>['Getting started','Everyone','Learn the navigation, profile settings, default contact view, and where to find key work.','<h2>Your first five minutes</h2><ol><li>Open <strong>User settings</strong> from your username to set your display name, timezone, notification preferences, and automatic contact tags.</li><li>Open <strong>Contacts</strong>. The default tab shows contacts you own; use Actions to switch to all contacts you are permitted to see.</li><li>Create a contact, add searchable tags, notes, relationships, and reminders.</li><li>Use Opportunities to track qualified work and Alerts to see due and upcoming tasks.</li><li>Use the Help link at any time to return here.</li></ol><div class="callout"><strong>Record ownership:</strong> users may add notes to visible contacts, but only the creator, assigned owner, or a system administrator can change the record.</div>'],
 'contacts'=>['Contacts, companies, and tags','CRM users','Create, import, organize, deduplicate, and maintain contact records.','<h2>Contacts</h2><p>Use <strong>Add contact</strong> for individual records. The Actions menu contains CSV/Excel import, export, saved views, My Contacts/All Contacts, and bulk reassignment.</p><h3>Duplicate checks</h3><p>OpenCRM checks email, phone, name, and similar company names. Review “Did you mean?” suggestions before creating a new company spelling.</p><h3>Tags and custom fields</h3><p>Search for tags by typing. Tags can be organized into groups, protected by tag-level permissions, and used to reveal conditional custom fields. Administrators manage definitions under Admin settings.</p><h3>Inactive records</h3><p>Inactive contacts are hidden from the normal list but remain searchable and reportable. Use inactive status instead of deleting historical records.</p>'],
 'opportunities'=>['Opportunities and pipeline','Sales users','Create opportunities, move pipeline stages, attribute sources, and archive old work.','<h2>Pipeline workflow</h2><p>Create an opportunity from the Opportunities page or a contact Quick Action. Link one or more contacts, select a score and stage, enter value and expected close date, and attribute its source to an event or a note.</p><p>Drag cards between configurable pipeline stages. Won and Lost remain available for historical reporting. Archive opportunities instead of deleting them.</p><h3>Partner sales</h3><p>Authorized users can review pipeline, recent closes, due work, and performance by partner. Non-administrators see only the sales data granted to them.</p>'],
 'events-promotions'=>['Events and promotional links','Marketing users','Manage events, attendees, presenters, QR codes, campaign links, and analytics.','<h2>Events</h2><p>Track event name, presentation title, abstract, URLs, conference address, slides, multiple contact or CRM-user presenters, and attendees. Imports can add attendees in bulk. Attendance applies an <code>EventName_EventType</code> tag for reporting.</p><h2>Promotional links</h2><p>Create separate tracked links for each channel, post, campaign day, or message even when they share a destination. OpenCRM warns about duplicate destinations without preventing intentional variants. Analytics include clicks, unique visitors, referrers, devices, and UTM information.</p>'],
 'forms'=>['Forms and lead capture','Marketing users','Build public/private forms, map CRM fields, apply tags, validate entries, and deliver downloads.','<h2>Building forms</h2><p>Add fields, labels, required rules, validation patterns, conditional visibility, and calculations. Map fields to standard CRM properties and configure fixed tags or value-to-tag mappings.</p><h3>Public behavior</h3><p>Public forms do not require authentication. On submission, OpenCRM checks for an existing contact, updates changed mapped information, applies tags, records the conversion, displays the thank-you message, and can start a published lead-magnet download.</p><p>Use the generated <code>/f/form-code</code> URL directly or embed the form in a Site page.</p>'],
 'lead-magnets'=>['AI lead magnets','Authorized creators','Generate branded documents from the knowledge base, refine them, download, and publish.','<h2>Generate and refine</h2><p>Select the artifact type, describe the audience, problem, desired outcome, tone, and call to action. The generator combines those answers with the administrator-managed knowledge base and application branding.</p><p>Continue refining through the conversation panel. Save edits, export PDF or DOCX, or publish a stable public URL that can be used by forms, promotional links, and QR codes.</p><div class="callout">AI output should always be reviewed for accuracy, claims, and brand compliance before publication.</div>'],
 'sites'=>['Sites and landing pages','Site editors','Build pages with GrapesJS, forms, bookings, assets, versions, analytics, SEO, and domains.','<h2>Visual editor</h2><p>Start from a lead-generation, event, or service template; drag layout, CRM Form, and Booking blocks; upload managed images; or import HTML and CSS. Save drafts before publishing.</p><h3>Versions and SEO</h3><p>Every save creates a restorable version. Configure browser title, description, canonical URL, social title/image/description, and search-engine visibility in Page tools.</p><h3>Analytics and consent</h3><p>Site settings control analytics and consent mode. Tracked visits capture privacy-conscious session, page, engagement, referrer, device, and UTM information. Forms and bookings attribute the resulting CRM contact and conversion.</p><h3>Custom domains</h3><p>Add a domain under the site’s Domains page, publish the displayed TXT verification record, point DNS to this server, and click Check DNS. After verification, the scheduled provisioner configures HTTPS automatically. Use path redirects when URLs change.</p>'],
 'bookings'=>['Bookings and calendars','Booking users','Configure public booking pages, availability, questions, reminders, and external calendars.','<h2>Booking setup</h2><p>Booking calendars define the owner, timezone, availability, buffers, minimum notice, and meeting types. Meeting types can include custom questions and contact tags. Public booking URLs do not require a CRM login.</p><h3>Calendar conflicts</h3><p>Connect Google Calendar, Microsoft 365, or CalDAV from User settings → Connected calendars. External busy periods are removed from both native and Easy!Appointments availability. The health status shows the last successful check or error.</p><h3>Lifecycle</h3><p>Guests receive confirmation and a secure management link for rescheduling or cancellation. The host receives notifications, reminders run at 24 hours and 1 hour, and the contact receives a CRM note and configured tags.</p>'],
 'reports-alerts'=>['Reports, alerts, and saved views','Everyone','Build focused reports, use saved contact views, and manage personal or assigned reminders.','<h2>Reports</h2><p>Choose a dataset, then use Add Filter to select only the criteria you need. Contacts, custom fields, tags, updated dates, active status, opportunities/pipeline items, and events can be filtered. Results default to a table with an optional chart. Save useful definitions for reuse.</p><h2>Alerts</h2><p>Alerts are private to the assigned user. Set one-time or recurring reminders, assign work to another user, use configurable snooze periods, and toggle the upcoming 30-day view. Administrators may issue system alerts visible to everyone.</p><h3>Saved contact views</h3><p>Save filters and visible columns as profile-owned tabs, and choose a personal default view.</p>'],
 'administration'=>['Administration guide','Administrators','Users, permissions, lists, security, mail, audit, logs, branding, and system health.','<h2>Core administration</h2><ul><li><strong>Application settings:</strong> application name, logo, colors, timezone, and general behavior.</li><li><strong>Users and roles:</strong> create users, reset passwords, grant feature permissions, and control tag visibility/read/write access.</li><li><strong>Dropdowns:</strong> centrally maintain stages, statuses, scores, snooze periods, and other configurable lists.</li><li><strong>Tags/custom fields:</strong> manage groups, conditional rules, options, and security.</li><li><strong>Audit:</strong> review sign-ins and record actions. Application logs have configurable levels and retention cleanup.</li><li><strong>Mail:</strong> configure local transport or SMTP and send a test message.</li><li><strong>System health:</strong> check runtime, storage, database, scheduled jobs, and integrations.</li></ul><div class="callout"><strong>Public repository safety:</strong> secrets belong in encrypted application settings or the server environment—never source files.</div>'],
 'integrations-api'=>['Integrations and API','Administrators and integrators','Connect GHL/webhooks, calendars, mail, OpenAI, and Easy!Appointments safely.','<h2>Contact API</h2><p>Create an API user under Admin → API users. Copy the bearer token once and send it in the configured authentication header. Choose create-only when an automation must never modify or delete CRM content.</p><p>GoHighLevel-style flat bodies may provide standard contact keys, <code>tag</code>, <code>tag1</code>, <code>tag2</code>, and custom fields such as <code>custom_Customer_Type</code>. Notes can be supplied during contact creation.</p><h3>Other integrations</h3><ul><li>Configure encrypted OpenAI credentials and the knowledge base under AI setup.</li><li>Configure Google/Microsoft OAuth application credentials under Calendar integrations; users connect their own accounts.</li><li>CalDAV users connect with a calendar URL and app password.</li><li>Easy!Appointments mappings are managed under Booking engine.</li><li>Use Mail settings for SES or another SMTP provider.</li></ul>'],
 'troubleshooting'=>['Troubleshooting','Everyone','Resolve access, validation, email, calendar, site, and webhook problems.','<h2>First checks</h2><ol><li>Confirm you are signed in and have the relevant feature permission.</li><li>Reload the page after a role or tag-permission change.</li><li>Check whether the record is owned by you or explicitly assigned to you.</li><li>For imports, download the template and review the preview before confirming.</li><li>For integrations, check Admin → System health and Application logs.</li></ol><h3>Common integration issues</h3><p>SMTP 535 errors are provider authentication-policy failures, not CRM password failures. Calendar errors normally require reconnecting the user account. Webhook payloads and unmatched endpoints appear in application logs at the configured level.</p><h3>Getting support</h3><p>Provide the approximate time, signed-in username, page URL, action attempted, and visible error. Do not email passwords, API tokens, private keys, or unredacted webhook secrets.</p>']
];}

if($path==='/help'||preg_match('#^/help/([a-z0-9-]+)$#',$path,$m)){
 require_login();$articles=help_articles();$key=$m[1]??'';if($key!==''){$article=$articles[$key]??null;if(!$article){http_response_code(404);exit('Help article not found');}if($article[1]==='Administrators'&&!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}layout($article[0],function()use($article){?><div class="actions"><h1 style="margin:0"><?=e($article[0])?></h1><span class="spacer"></span><a class="btn secondary" href="/help">All help</a></div><div class="card"><p class="muted"><?=e($article[2])?> · Audience: <?=e($article[1])?></p><?=$article[3]?></div><?php });exit;}
 $query=mb_strtolower(trim((string)($_GET['q']??'')));if(!(user()['is_admin']??false))unset($articles['administration']);if($query!=='')$articles=array_filter($articles,fn($a)=>str_contains(mb_strtolower(implode(' ',array_slice($a,0,3)).' '.strip_tags($a[3])),$query));layout('Help Center',function()use($articles,$query){?><div class="actions"><h1 style="margin:0">Help Center</h1></div><form class="card actions" method="get"><label style="flex:1;margin:0">Search help<input name="q" value="<?=e($query)?>" placeholder="Try contacts, booking, API, reports…"></label><button>Search</button></form><div class="grid help-grid"><?php foreach($articles as $slug=>$a):?><a class="card help-card" href="/help/<?=e($slug)?>"><h2><?=e($a[0])?></h2><p><?=e($a[2])?></p><span class="muted"><?=e($a[1])?></span></a><?php endforeach?></div><?php if(!$articles):?><div class="card">No help articles matched that search.</div><?php endif?><?php });exit;
}
